// // This module implements a combinational logic circuit that produces an output Y based on the values of inputs A1, A2, and the negated input B1_N. The output Y is set to LOW (0) only when both A1 and A2 are HIGH. If A1 is HIGH and A2 is LOW, or if A1 is LOW and A2 is HIGH, the output Y is HIGH (1). In all other cases, when both A1 and A2 are LOW, the output Y takes the value of the negated input B1_N.
module top_module(
    input A1,
    input A2,
    input B1_N,
    output reg Y
);always @* begin
    if (A1 && A2) begin
        Y = 1;
    end else if (A1 && !A2) begin
        Y = 0;
    end else if (!A1 && A2) begin
        Y = 0;
    end else begin
        Y = B1_N;
    end
end

endmodule
